<template><div class="page-container"><PageHeader eyebrow="LIVE CHAT" title="聊天中心" description="私聊、群聊与作品讨论"><el-button type="primary" @click="createDialog=true">新建会话</el-button></PageHeader><div class="chat-shell"><aside class="conversation-list"><button v-for="c in conversations" :key="c.id" :class="{active:String(c.id)===String(activeId)}" @click="select(c)"><div><strong>{{ c.title||conversationName(c) }}</strong><span>{{ c.lastMessageContent||'暂无消息' }}</span></div><el-badge :value="c.unreadCount" :hidden="!c.unreadCount"/></button><EmptyState v-if="!conversations.length" description="暂无会话"/></aside><section class="message-panel"><template v-if="active"><header class="message-header"><div><h2>{{ active.title||conversationName(active) }}</h2><span>{{ active.memberCount||0 }} 名成员</span></div><el-button text type="danger" @click="leave">退出会话</el-button></header><div ref="messageBox" class="message-list"><div v-for="m in messages" :key="m.id" :class="['message-row',{mine:String(m.senderId)===String(userId)}]"><div class="message-bubble"><small>用户 {{ m.senderId }} · {{ formatDate(m.createdAt) }}</small><p>{{ m.deleted?'[消息已删除]':m.content }}</p><el-button v-if="String(m.senderId)===String(userId)&&!m.deleted" text size="small" @click="removeMessage(m)">删除</el-button></div></div></div><footer class="message-compose"><el-input v-model="content" type="textarea" :rows="3" placeholder="输入消息，Ctrl+Enter 发送" @keydown.ctrl.enter="send"/><el-button type="primary" @click="send">发送</el-button></footer></template><EmptyState v-else description="选择一个会话开始聊天"/></section></div><el-dialog v-model="createDialog" title="新建会话" width="520"><el-tabs v-model="createType"><el-tab-pane label="私聊" name="private"><el-input v-model="createForm.peerUserId" placeholder="对方用户 ID"/></el-tab-pane><el-tab-pane label="群聊" name="group"><el-input v-model="createForm.title" placeholder="群聊名称"/><el-input v-model="memberText" style="margin-top:12px" placeholder="成员用户 ID，以逗号分隔"/></el-tab-pane><el-tab-pane label="作品群" name="work"><el-input v-model="createForm.workId" placeholder="作品 ID"/><el-input v-model="createForm.title" style="margin-top:12px" placeholder="讨论组名称"/></el-tab-pane></el-tabs><template #footer><el-button @click="createDialog=false">取消</el-button><el-button type="primary" @click="createConversation">创建</el-button></template></el-dialog></div></template>
<script setup>import { computed,nextTick,onBeforeUnmount,onMounted,reactive,ref } from 'vue';import { useRoute } from 'vue-router';import PageHeader from '../../components/PageHeader.vue';import EmptyState from '../../components/EmptyState.vue';import { chatApi } from '../../api/chat';import { authStore } from '../../stores/auth';import { formatDate } from '../../utils/format';const route=useRoute(),conversations=ref([]),activeId=ref(route.query.conversationId||''),messages=ref([]),content=ref(''),createDialog=ref(false),createType=ref('private'),memberText=ref(''),createForm=reactive({peerUserId:'',workId:'',title:''}),messageBox=ref(null);const userId=computed(()=>authStore.state.user?.id||authStore.state.user?.userId),active=computed(()=>conversations.value.find(c=>String(c.id)===String(activeId.value)));let timer;function conversationName(c){return `${c.conversationType||'会话'} #${c.id}`}async function loadConversations(){conversations.value=await chatApi.mine();if(activeId.value){const target=conversations.value.find(c=>String(c.id)===String(activeId.value));if(target)select(target)}else if(conversations.value[0])select(conversations.value[0])}async function select(c){activeId.value=c.id;messages.value=await chatApi.messages(c.id,{page:0,size:100});await chatApi.read(c.id);nextTick(()=>{if(messageBox.value)messageBox.value.scrollTop=messageBox.value.scrollHeight})}async function send(){if(!content.value.trim()||!active.value)return;await chatApi.send(activeId.value,content.value.trim());content.value='';select(active.value)}async function removeMessage(m){await chatApi.removeMessage(m.id);select(active.value)}async function leave(){await chatApi.leave(activeId.value);activeId.value='';messages.value=[];loadConversations()}async function createConversation(){let c;if(createType.value==='private')c=await chatApi.createPrivate(createForm.peerUserId);else if(createType.value==='group')c=await chatApi.createGroup(createForm.title,memberText.value.split(',').map(v=>v.trim()).filter(Boolean));else c=await chatApi.createWork(createForm.workId,createForm.title);createDialog.value=false;await loadConversations();activeId.value=c.id;select(c)}onMounted(()=>{loadConversations();timer=setInterval(()=>{if(active.value)select(active.value)},5000)});onBeforeUnmount(()=>clearInterval(timer))</script>
